const req = $('Normalizar solicitud').first().json;
const tema = req.tema;
const pregunta = req.pregunta;
const datos = [
  { etiqueta: '2021', valor: 18, unidad: 'indice 0-100', periodo: '2021', fuente_url: 'https://ejemplo.demo/indice-adopcion' },
  { etiqueta: '2022', valor: 24, unidad: 'indice 0-100', periodo: '2022', fuente_url: 'https://ejemplo.demo/indice-adopcion' },
  { etiqueta: '2023', valor: 31, unidad: 'indice 0-100', periodo: '2023', fuente_url: 'https://ejemplo.demo/indice-adopcion' },
  { etiqueta: '2024', valor: 47, unidad: 'indice 0-100', periodo: '2024', fuente_url: 'https://ejemplo.demo/indice-adopcion' },
  { etiqueta: '2025', valor: 58, unidad: 'indice 0-100', periodo: '2025', fuente_url: 'https://ejemplo.demo/indice-adopcion' }
];
const cfg = {
  type: 'line',
  data: { labels: datos.map(d => d.etiqueta), datasets: [{ label: ('Indice de interes: ' + tema).slice(0, 80), data: datos.map(d => d.valor), borderColor: '#2563eb', backgroundColor: 'rgba(37,99,235,0.15)', fill: true }] },
  options: { plugins: { title: { display: true, text: ('Evolucion (DATOS DEMO): ' + tema).slice(0, 90) } } }
};
const grafico_url = 'https://quickchart.io/chart?w=620&h=360&bkg=white&c=' + encodeURIComponent(JSON.stringify(cfg));
const hechos = [
  { afirmacion: 'DEMO: hecho de ejemplo 1 sobre ' + tema + ' (en produccion saldria de la busqueda con fuentes reales).', fuente_url: 'https://ejemplo.demo/fuente-1' },
  { afirmacion: 'DEMO: hecho de ejemplo 2 con dato numerico y su fuente.', fuente_url: 'https://ejemplo.demo/fuente-2' }
];

// Fase 4 simulada: verificacion adversarial y puntaje de confianza (en produccion lo produce Gemini).
const puntaje_calidad = 82;
const nivel_confianza = 'alto';
const veredicto = 'DEMO: informe consistente; los 2 hechos tienen fuente y la serie es coherente. En produccion este veredicto proviene de la auditoria adversarial real.';
const senales_alerta = ['DEMO: los datos son de ejemplo, no de fuentes reales.'];
const limitaciones = ['DEMO: sin busqueda web; las cifras no representan la realidad.'];

const md = [
  '# ' + tema,
  '',
  '**Pregunta central:** ' + pregunta,
  '',
  '**Confianza de la investigacion:** ' + puntaje_calidad + '/100 (' + nivel_confianza + '). ' + veredicto,
  '',
  '**Respuesta corta (DEMO):** Esta es una ejecucion de demostracion sin credenciales; en produccion aqui va la respuesta directa sustentada en fuentes reales.',
  '',
  '## Hechos verificados',
  ...hechos.map(h => '- ' + h.afirmacion + ' [fuente: ' + h.fuente_url + ']'),
  '',
  '## El porque (5 porques)',
  '- Por que 1: causa inmediata de ejemplo.',
  '- Por que 2: causa intermedia de ejemplo.',
  '- Por que 3: causa estructural de ejemplo.',
  '',
  '## Graficos',
  '- Evolucion temporal (DATOS DEMO): ' + grafico_url,
  '',
  '## Verificacion y confianza (auditoria adversarial)',
  '- Puntaje de confianza: ' + puntaje_calidad + '/100 (' + nivel_confianza + ').',
  '- Veredicto: ' + veredicto,
  '- Senales de alerta:',
  ...senales_alerta.map(s => '  - ' + s),
  '- Limitaciones:',
  ...limitaciones.map(l => '  - ' + l),
  '',
  '## Fuentes',
  '- [demo] Fuente de ejemplo 1 - https://ejemplo.demo/fuente-1',
  '- [demo] Fuente de ejemplo 2 - https://ejemplo.demo/fuente-2'
];
return [{ json: {
  ...req,
  nota_demo: 'DEMO: investigacion simulada sin credenciales. El grafico QuickChart SI es real y se genera en vivo. En produccion los datos provienen de Gemini con Google Search grounding y el puntaje de confianza de la fase de verificacion adversarial.',
  respuesta_corta: 'Respuesta corta de demostracion para: ' + pregunta,
  resumen: 'Resumen de demostracion sobre "' + tema + '". El flujo de produccion realiza 3 fases de investigacion con grounding (base, profundizacion, sintesis JSON) y una 4a fase de verificacion adversarial que asigna el puntaje de confianza.',
  hechos,
  datasets: [{ titulo: 'Evolucion (DATOS DEMO): ' + tema, tipo_grafico: 'lineas', datos, quickchart_url: grafico_url }],
  grafico_url,
  puntaje_calidad,
  nivel_confianza,
  veredicto,
  senales_alerta,
  limitaciones,
  informe_markdown: md.join('\n')
} }];

const req = $('Normalizar solicitud').first().json;
const tema = req.tema;
const preguntas = [
  { pregunta: 'Que dice la evidencia mas reciente sobre ' + tema + '?', por_que_interesa: 'Establece la base factual con fuentes primarias', angulo: 'datos' },
  { pregunta: 'Por que esta creciendo (o frenandose) ' + tema + '?', por_que_interesa: 'Aplica los 5 porques hasta la causa estructural', angulo: 'causas' },
  { pregunta: 'Que mitos circulan sobre ' + tema + ' y cuales resisten la evidencia?', por_que_interesa: 'Separa hechos de opiniones; ideal para compartir', angulo: 'mitos' },
  { pregunta: 'Quien gana y quien pierde con ' + tema + '?', por_que_interesa: 'Revela incentivos e impacto real', angulo: 'impacto' }
];
return [{ json: { ...req, preguntas, nota_demo: 'DEMO: preguntas generadas con plantilla local, sin llamar a la API de Gemini.' } }];
